// Get previous month boundaries
const now = new Date();
const prevMonthDate = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const prevMonthEnd = new Date(now.getFullYear(), now.getMonth(), 0);
const month = `${prevMonthDate.getFullYear()}-${String(prevMonthDate.getMonth() + 1).padStart(2, '0')}`;
const monthLabel = prevMonthDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' });
const monthStart = prevMonthDate.toISOString().split('T')[0];
const monthEnd = prevMonthEnd.toISOString().split('T')[0];

// Filter analysis results to previous month
const allAnalysis = $('Read Analysis Results').all().map(i => i.json);
const analysisRows = allAnalysis.filter(row => {
  const date = (row.analyzed_at || row[13] || '').split('T')[0];
  return date >= monthStart && date <= monthEnd;
});

// Filter accuracy log to previous month
const allAccuracy = $('Read Accuracy Log').all().map(i => i.json);
const accuracyRows = allAccuracy.filter(row => {
  const date = row.date || row[0] || '';
  return date >= monthStart && date <= monthEnd;
});

// Filter alert log to previous month
const allAlerts = $('Read Alert Log').all().map(i => i.json);
const alertRows = allAlerts.filter(row => {
  const date = row.date || row[1] || '';
  return date >= monthStart && date <= monthEnd;
});

// Compile analysis metrics
const totalConversations = analysisRows.length;
const severityCounts = { Critical: 0, High: 0, Medium: 0, Low: 0 };
const categoryCounts = {};
const agentScores = {};
const resolutionCounts = { Resolved: 0, Unresolved: 0, 'Partially Resolved': 0 };

for (const row of analysisRows) {
  const severity = row.severity || row[4] || 'Low';
  const category = row.issue_category || row[5] || 'Other';
  const resolution = row.resolution_status || row[6] || 'Unresolved';
  const agentName = row.agent_name || row[2] || 'Unknown';
  const agentScore = parseInt(row.agent_score || row[8] || 3, 10);
  if (severityCounts.hasOwnProperty(severity)) severityCounts[severity]++;
  categoryCounts[category] = (categoryCounts[category] || 0) + 1;
  if (resolutionCounts.hasOwnProperty(resolution)) resolutionCounts[resolution]++;
  if (!agentScores[agentName]) agentScores[agentName] = { total: 0, count: 0 };
  agentScores[agentName].total += agentScore;
  agentScores[agentName].count++;
}

const satisfactionRate = totalConversations > 0 ? Math.round((severityCounts.Low / totalConversations) * 1000) / 10 : 0;
const resolutionRate = totalConversations > 0 ? Math.round((resolutionCounts.Resolved / totalConversations) * 1000) / 10 : 0;

const topIssues = Object.entries(categoryCounts).sort((a, b) => b[1] - a[1]).slice(0, 10).map(([category, count]) => ({ category, count, pct_of_total: totalConversations > 0 ? Math.round((count / totalConversations) * 1000) / 10 : 0 }));

const agentRankings = Object.entries(agentScores).map(([name, data]) => ({ agent_name: name, avg_score: Math.round((data.total / data.count) * 10) / 10, conversation_count: data.count })).sort((a, b) => b.avg_score - a.avg_score);

// Accuracy metrics
const avgAccuracy = accuracyRows.length > 0 ? Math.round(accuracyRows.reduce((sum, r) => sum + parseFloat(r.accuracy_rate || r[4] || 0), 0) / accuracyRows.length * 1000) / 1000 : null;
const catDisagreements = {};
for (const row of accuracyRows) { const cat = row.worst_category || row[5] || ''; if (cat && cat !== 'N/A') catDisagreements[cat] = (catDisagreements[cat] || 0) + 1; }
const worstAccuracyCategory = Object.entries(catDisagreements).sort((a, b) => b[1] - a[1])[0]?.[0] || 'N/A';

// Alert metrics
const totalAlerts = alertRows.length;
const criticalAlerts = alertRows.filter(r => (r.severity || r[5]) === 'Critical').length;

const metrics = { month: monthLabel, month_id: month, total_conversations: totalConversations, severity_breakdown: severityCounts, satisfaction_rate: satisfactionRate, resolution_rate: resolutionRate, top_issues: topIssues, agent_rankings: agentRankings, ai_accuracy_rate: avgAccuracy, worst_accuracy_category: worstAccuracyCategory, total_alerts: totalAlerts, critical_alerts: criticalAlerts };

return [{ json: { month, month_label: monthLabel, total_conversations: totalConversations, satisfaction_rate: satisfactionRate, top_issues: JSON.stringify(topIssues), accuracy_rate: avgAccuracy || 0, metrics_json: JSON.stringify(metrics, null, 2) } }];

